CREATE TABLE `invoice` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `invoice_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `issue_date` date NOT NULL,
  `due_date` date NOT NULL,
  `currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `subtotal` decimal(12,2) NOT NULL,
  `tax_amount` decimal(12,2) NOT NULL,
  `total_amount` decimal(12,2) NOT NULL,
  `notes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `created_by_id` int DEFAULT NULL,
  `customer_id` bigint NOT NULL,
  `public_view_token` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `view_count` int unsigned NOT NULL,
  `viewed_at` datetime(6) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `invoice_number` (`invoice_number`),
  KEY `invoicing_i_invoice_f2b05e_idx` (`invoice_number`),
  KEY `invoicing_i_status_2eeee5_idx` (`status`),
  KEY `invoicing_i_issue_d_436aef_idx` (`issue_date`),
  KEY `invoicing_i_due_dat_92e42f_idx` (`due_date`),
  KEY `invoicing_invoice_created_by_id_e228794d_fk_auth_user_id` (`created_by_id`),
  KEY `invoicing_invoice_customer_id_c1b6ead9_fk_invoicing_customer_id` (`customer_id`),
  KEY `invoicing_i_public__aa0d66_idx` (`public_view_token`),
  KEY `invoicing_invoice_public_view_token_893ce866` (`public_view_token`),
  CONSTRAINT `invoicing_invoice_created_by_id_e228794d_fk_auth_user_id` FOREIGN KEY (`created_by_id`) REFERENCES `user` (`id`),
  CONSTRAINT `invoicing_invoice_customer_id_c1b6ead9_fk_invoicing_customer_id` FOREIGN KEY (`customer_id`) REFERENCES `customer` (`id`),
  CONSTRAINT `invoice_chk_1` CHECK ((`view_count` >= 0)),
  CONSTRAINT `invoice_due_on_or_after_issue` CHECK ((`due_date` >= `issue_date`)),
  CONSTRAINT `invoice_subtotal_non_negative` CHECK ((`subtotal` >= 0)),
  CONSTRAINT `invoice_tax_non_negative` CHECK ((`tax_amount` >= 0)),
  CONSTRAINT `invoice_total_non_negative` CHECK ((`total_amount` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
